"use client";

import { useEffect, useRef, useState } from "react";
import { usePathname, useSearchParams } from "next/navigation";
import { ArrowUp } from "lucide-react";
import { Button } from "@ui/components/button";
import { cn } from "@ui/lib/utils";
import { getHeaderHeight, scrollToYWithHeaderOffset } from "@/lib/scroll";

const scrollAllToTop = (behavior: ScrollBehavior = "instant") => {
  scrollToYWithHeaderOffset(0, behavior);

  const mainElement = document.querySelector("main");
  if (mainElement instanceof HTMLElement) {
    const headerHeight = getHeaderHeight();
    const nextTop = Math.max(0 - headerHeight, 0);
    mainElement.scrollTo({ top: nextTop, left: 0, behavior });
  }
};

export function ScrollToTop() {
  const pathname = usePathname();
  const searchParams = useSearchParams();
  const previousPathnameRef = useRef<string | null>(null);
  const previousSearchParamsRef = useRef<string | null>(null);
  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    const currentSearchParams = searchParams?.toString() ?? null;
    const pathnameChanged =
      previousPathnameRef.current !== null && previousPathnameRef.current !== pathname;
    const searchParamsChanged =
      previousSearchParamsRef.current !== null &&
      previousSearchParamsRef.current !== currentSearchParams;

    if (pathnameChanged || searchParamsChanged) {
      requestAnimationFrame(() => {
        scrollAllToTop("instant");
      });
    }

    previousPathnameRef.current = pathname;
    previousSearchParamsRef.current = currentSearchParams;
  }, [pathname, searchParams]);

  useEffect(() => {
    const handleScroll = () => {
      const mainElement = document.querySelector("main");
      const mainScroll = mainElement instanceof HTMLElement ? mainElement.scrollTop : 0;
      const windowScroll = window.scrollY || window.pageYOffset;

      setIsVisible(windowScroll > 300 || mainScroll > 300);
    };

    window.addEventListener("scroll", handleScroll, { passive: true });

    const mainElement = document.querySelector("main");
    if (mainElement instanceof HTMLElement) {
      mainElement.addEventListener("scroll", handleScroll, { passive: true });
    }

    handleScroll();

    return () => {
      window.removeEventListener("scroll", handleScroll);
      if (mainElement instanceof HTMLElement) {
        mainElement.removeEventListener("scroll", handleScroll);
      }
    };
  }, []);

  return (
    <Button
      type="button"
      size="icon"
      aria-label="Cuộn lên đầu trang"
      onClick={() => scrollAllToTop("smooth")}
      className={cn(
        "fixed bottom-20 right-3 z-50 h-12 w-12 rounded-full shadow-lg transition-all duration-300",
        "bg-secondary text-secondary-foreground hover:bg-secondary/90",
        "hover:scale-110 active:scale-95",
        isVisible ? "pointer-events-auto translate-y-0 opacity-100" : "pointer-events-none translate-y-4 opacity-0"
      )}
    >
      <ArrowUp className="h-5 w-5" />
    </Button>
  );
}

src/components/shared/store-auth-gate.ts.content:
"use client";

import { useEffect, type ReactNode } from "react";
import { usePathname, useRouter } from "next/navigation";
import { Loader2 } from "lucide-react";
import { useSession } from "@/hooks/use-session";
import { useClientReady } from "@/hooks/use-client-ready";
import { isStoreAuthPath, safeRelativeNext } from "@/lib/auth-routes";

function AuthRoutePlaceholder({ message }: { message: string }) {
  return (
    <div className="flex min-h-[min(70vh,calc(100vh-12rem))] w-full flex-1 flex-col items-center justify-center gap-3 text-muted-foreground">
      <Loader2 className="size-10 animate-spin text-primary" aria-hidden />
      <p className="text-sm">{message}</p>
    </div>
  );
}

/**
 * Chặn người đã đăng nhập quay lại /login hoặc /register (kể cả nút Back / gõ URL).
 * Giữ tham số `next` hợp lệ khi rời /login.
 */
export function StoreAuthGate({ children }: { children: ReactNode }) {
  const pathname = usePathname();
  const router = useRouter();
  const session = useSession();
  const clientReady = useClientReady();
  const onAuthRoute = isStoreAuthPath(pathname);

  useEffect(() => {
    if (!clientReady || !onAuthRoute || !session) return;
    const raw =
      typeof window !== "undefined"
        ? new URLSearchParams(window.location.search).get("next")
        : null;
    router.replace(safeRelativeNext(raw));
  }, [clientReady, onAuthRoute, session, router]);

  if (!onAuthRoute) {
    return <>{children}</>;
  }

  if (!clientReady) {
    return <AuthRoutePlaceholder message="Đang tải…" />;
  }

  if (session) {
    return <AuthRoutePlaceholder message="Đang chuyển vào hệ thống…" />;
  }

  return <>{children}</>;
}

