import Image from "next/image";
import { TypographyH2, TypographyDescriptionLarge, TypographyPSmallMuted, IconSize, TypographyH3 } from "@ui/components/typography";
import { ChevronLeft, ChevronRight } from "lucide-react";
import { Button } from "@ui/components/button";
import { useState } from "react";
import { FACILITIES, FACILITY_IMAGES } from "../constants";

export const FacilitiesSection = () => {
  const [currentImageIndex, setCurrentImageIndex] = useState(0);

  const nextImage = () => {
    setCurrentImageIndex((prev) => (prev + 1) % FACILITY_IMAGES.length);
  };

  const prevImage = () => {
    setCurrentImageIndex((prev) => (prev - 1 + FACILITY_IMAGES.length) % FACILITY_IMAGES.length);
  };

  return (
    <section className="py-12 sm:py-16 lg:py-20 bg-muted/30">
      <div className="w-full mx-auto max-w-[1440px] px-6 md:px-12">
        <div className="max-w-4xl mx-auto text-center mb-10 sm:mb-16">
          <TypographyH2 className="mb-4 sm:mb-6">
            Cơ sở vật chất hiện đại
          </TypographyH2>
          <TypographyDescriptionLarge>
            <span className="text-secondary font-bold text-lg sm:text-xl">HUB</span> sở hữu
            hệ thống cơ sở vật chất hiện đại, đáp ứng đầy đủ nhu cầu học tập,
            nghiên cứu và sinh hoạt của sinh viên tại 03 cơ sở đào tạo.
          </TypographyDescriptionLarge>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 lg:gap-16 items-center">
          {/* Facilities List */}
          <div className="space-y-6">
            {FACILITIES.map((facility, index) => (
              <div key={index} className="flex gap-4 sm:gap-6 group">
                <div className="flex-shrink-0 w-10 sm:w-12 h-10 sm:h-12 rounded-full bg-primary/10 flex items-center justify-center text-primary group-hover:bg-primary group-hover:text-white transition-colors duration-300">
                  {facility.icon}
                </div>
                <div>
                  <TypographyH3 className="mb-1 sm:mb-2 group-hover:text-primary transition-colors text-lg font-bold">
                    {facility.title}
                  </TypographyH3> 
                  <TypographyPSmallMuted>
                    {facility.description}
                  </TypographyPSmallMuted>
                </div>
              </div>
            ))}
          </div>

          {/* Image Carousel */}
          <div className="relative group overflow-hidden rounded-lg sm:rounded-lg shadow-xl">
            <div className="aspect-[4/3] relative w-full">
              {FACILITY_IMAGES.map((image, index) => (
                <div
                  key={index}
                  className={`absolute inset-0 transition-opacity duration-700 ${
                    index === currentImageIndex ? "opacity-100" : "opacity-0"
                  }`}
                >
                  <Image
                    src={image.url}
                    alt={image.title}
                    title={image.title}
                    fill
                    className="object-cover article-image article-image-ux-impr article-image-new expandable"
                    sizes="(max-width: 640px) 100vw, (max-width: 1024px) 80vw, 50vw"
                    unoptimized
                    loading="eager"
                  />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />
                  <div className="absolute bottom-0 left-0 right-0 p-4 sm:p-6 text-white">
                    <p className="text-sm font-medium uppercase tracking-wider mb-1">
                      {image.category}
                    </p>
                    <TypographyH3 className="text-xl sm:text-2xl font-bold">
                      {image.title}
                    </TypographyH3>
                  </div>
                </div>
              ))}
            </div>

            {/* Carousel Controls */}
            <div className="absolute top-1/2 -translate-y-1/2 left-4 right-4 flex justify-between opacity-0 group-hover:opacity-100 transition-opacity duration-300">
              <Button
                variant="outline"
                size="icon"
                onClick={prevImage}
                aria-label="Hình ảnh trước"
                className="bg-white/20 backdrop-blur-md border-white/30 text-white hover:bg-white/40 rounded-full"
              >
                <IconSize size="sm">
                  <ChevronLeft />
                </IconSize>
              </Button>
              <Button
                variant="outline"
                size="icon"
                onClick={nextImage}
                aria-label="Hình ảnh tiếp theo"
                className="bg-white/20 backdrop-blur-md border-white/30 text-white hover:bg-white/40 rounded-full"
              >
                <IconSize size="sm">
                  <ChevronRight />
                </IconSize>
              </Button>
            </div>

            {/* Carousel Indicators */}
            <div className="absolute bottom-4 left-1/2 -translate-x-1/2 flex gap-2">
              {FACILITY_IMAGES.map((_, index) => (
                <button
                  key={index}
                  onClick={() => setCurrentImageIndex(index)}
                  className={`w-2 h-2 rounded-full transition-all duration-300 ${
                    index === currentImageIndex
                      ? "bg-white w-6"
                      : "bg-white/50 hover:bg-white/80"
                  }`}
                />
              ))}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

"use client";

import Image from "next/image";
import { useCallback, useRef, useState } from "react";
import { ChevronLeft, ChevronRight } from "lucide-react";
import { Button } from "@ui/components/button";
import {
  TypographyDescriptionLarge,
  TypographyH2,
  TypographyH3,
  TypographyPSmallMuted,
} from "@ui/components/typography";
import { HISTORY_TIMELINE } from "../constants";

export const HistorySection = () => {
  const sliderRef = useRef<HTMLDivElement>(null);
  const [activeIndex, setActiveIndex] = useState(0);
  const total = HISTORY_TIMELINE.length;

  const updateActiveIndex = useCallback(() => {
    const slider = sliderRef.current;
    if (!slider || total === 0) return;

    const threshold = 10;
    const atStart = slider.scrollLeft <= threshold;
    const atEnd =
      slider.scrollLeft + slider.clientWidth >= slider.scrollWidth - threshold;

    if (atStart) {
      setActiveIndex(0);
      return;
    }

    if (atEnd) {
      setActiveIndex(total - 1);
      return;
    }

    const itemEls = slider.querySelectorAll("[data-history-index]");
    let current = 0;
    let minDistance = Infinity;

    itemEls.forEach((el, index) => {
      const distance = Math.abs((el as HTMLElement).offsetLeft - slider.scrollLeft);
      if (distance < minDistance) {
        minDistance = distance;
        current = index;
      }
    });

    setActiveIndex(current);
  }, [total]);

  const scrollByCard = useCallback(
    (direction: "prev" | "next") => {
      const slider = sliderRef.current;
      if (!slider || total === 0) return;

      const firstItem = slider.querySelector("[data-history-index]") as HTMLElement | null;
      const gapPx = parseFloat(getComputedStyle(slider).gap) || 0;
      const step = firstItem ? firstItem.offsetWidth + gapPx : slider.clientWidth;

      slider.scrollBy({
        left: direction === "next" ? step : -step,
        behavior: "smooth",
      });
    },
    [total]
  );

  const goPrev = () => scrollByCard("prev");
  const goNext = () => scrollByCard("next");
  const canGoPrev = activeIndex > 0;
  const canGoNext = activeIndex < total - 1;

  return (
    <section className="bg-background py-16 sm:py-20">
      <div className="w-full mx-auto max-w-[1440px] px-6 md:px-12">
        <div className="grid gap-4 border-b pb-6 md:grid-cols-2 md:items-end">
          <div className="space-y-2">
            <TypographyPSmallMuted className="uppercase tracking-[0.22em] text-primary">
              Góc truyền thống
            </TypographyPSmallMuted>
            <TypographyH2 className="mb-0">
              Lịch sử hình thành & Phát triển
            </TypographyH2>
          </div>
          <TypographyDescriptionLarge className="max-w-3xl md:ml-auto">
            Đại học Ngân hàng có lịch sử hình thành và phát triển lâu đời, với
            nhiều truyền thống quý báu được gìn giữ và phát huy qua nhiều thế hệ.
          </TypographyDescriptionLarge>
        </div>

        <div className="space-y-6 pt-8">
          <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
            <TypographyH3 className="text-primary">
              Lịch sử hình thành
            </TypographyH3>
            <div className="flex items-center gap-2 self-start sm:self-auto">
              <Button
                type="button"
                variant="outline"
                size="icon"
                onClick={goPrev}
                disabled={!canGoPrev}
                aria-label="Slide trước"
                className="size-10 rounded-full border-border bg-background shadow-sm"
              >
                <ChevronLeft className="size-4" />
              </Button>
              <Button
                type="button"
                variant="outline"
                size="icon"
                onClick={goNext}
                disabled={!canGoNext}
                aria-label="Slide tiếp theo"
                className="size-10 rounded-full border-border bg-background shadow-sm"
              >
                <ChevronRight className="size-4" />
              </Button>
            </div>
          </div>

          <div className="-mx-6 px-6 md:mx-0 md:px-0">
            <div
              ref={sliderRef}
              onScroll={updateActiveIndex}
              className="flex snap-x snap-mandatory gap-4 overflow-x-auto pb-2 [scrollbar-width:none] [&::-webkit-scrollbar]:hidden"
              role="region"
              aria-label="Slider lịch sử hình thành và phát triển HUB"
            >
              {HISTORY_TIMELINE.map((item, index) => (
                <article
                  key={item.year}
                  data-history-index={index}
                  className="w-[320px] shrink-0 snap-start transition-all sm:w-[360px] lg:w-[420px]"
                >
                  <div className="relative aspect-[4/2] w-full overflow-hidden rounded-lg shadow-sm transition-all hover:-translate-y-0.5 hover:shadow-md">
                    <Image
                      src={item.image}
                      alt={item.year}
                      title={item.year}
                      fill
                      className="object-cover article-image article-image-ux-impr article-image-new expandable"
                      sizes="(max-width: 768px) 320px, (max-width: 1280px) 50vw, 33vw"
                      unoptimized
                    />
                  </div>
                  <div className="space-y-2 px-1 pt-4">
                    <p className="text-base font-bold tracking-tight text-[#c84b31] sm:text-lg">
                      {item.year}
                    </p>
                    <h4 className="text-[clamp(2rem,4vw,3.5rem)] font-black leading-none tracking-tight text-transparent [-webkit-text-stroke:1px_rgba(148,163,184,0.95)]">
                      {item.year}
                    </h4>
                    <p className="line-clamp-5 text-sm leading-relaxed text-muted-foreground sm:text-base">
                      {item.description}
                    </p>
                  </div>
                </article>
              ))}
            </div>

            <div className="mt-5 flex items-center justify-center gap-2">
              {HISTORY_TIMELINE.map((item, index) => (
                <button
                  key={`${item.year}-indicator`}
                  type="button"
                  onClick={() => {
                    const slider = sliderRef.current;
                    const target = slider?.querySelector(
                      `[data-history-index="${index}"]`
                    ) as HTMLElement | null;
                    target?.scrollIntoView({
                      behavior: "smooth",
                      block: "nearest",
                      inline: "start",
                    });
                  }}
                  aria-label={`Đi tới giai đoạn ${item.year}`}
                  aria-pressed={index === activeIndex}
                  className={
                    index === activeIndex
                      ? "h-2.5 w-8 rounded-full bg-primary transition-all"
                      : "h-2.5 w-2.5 rounded-full bg-border transition-all hover:bg-primary/40"
                  }
                />
              ))}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

import Image from "next/image";
import { TypographyH2, TypographyDescriptionLarge, TypographyH3, TypographyPSmallMuted, IconSize } from "@ui/components/typography";
import { ChevronLeft, ChevronRight } from "lucide-react";
import { Button } from "@ui/components/button";
import { useState } from "react";
import { LEADER_GENERATIONS } from "../constants";

export const LeadersSection = () => {
  const [currentLeaderIndex, setCurrentLeaderIndex] = useState(0);

  const nextLeader = () => {
    setCurrentLeaderIndex((prev) => (prev + 1) % LEADER_GENERATIONS.length);
  };

  const prevLeader = () => {
    setCurrentLeaderIndex((prev) => (prev - 1 + LEADER_GENERATIONS.length) % LEADER_GENERATIONS.length);
  };

  return (
    <section className="py-12 sm:py-16 lg:py-20 overflow-hidden">
      <div className="w-full mx-auto max-w-[1440px] px-6 md:px-12">
        <div className="max-w-4xl mx-auto text-center mb-10 sm:mb-16">
          <TypographyH2 className="mb-4 sm:mb-6">
            Lãnh đạo qua các thời kỳ
          </TypographyH2>
          <TypographyDescriptionLarge>
            Tri ân những đóng góp to lớn của các thế hệ lãnh đạo đã xây dựng
            và phát triển <span className="text-secondary font-bold text-lg sm:text-xl">HUB</span>.
          </TypographyDescriptionLarge>
        </div>

        <div className="relative max-w-5xl mx-auto px-4 sm:px-12">
          <div className="flex transition-transform duration-500 ease-in-out">
            <div className="w-full flex-shrink-0">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 sm:gap-8">
                {LEADER_GENERATIONS[currentLeaderIndex].leaders.map((leader, lIdx) => (
                  <div
                    key={lIdx}
                    className="flex flex-col items-center text-center p-4 sm:p-6 rounded-lg bg-muted/30 hover:bg-muted/50 transition-colors group"
                  >
                    <div className="relative w-32 h-32 sm:w-40 sm:h-40 mb-4 sm:mb-6 rounded-full overflow-hidden border-4 border-background shadow-lg group-hover:border-primary/30 transition-all">
                      <Image
                        src={leader.image}
                        alt={leader.name}
                        title={leader.name}
                        fill
                        className="object-cover article-image article-image-ux-impr article-image-new expandable"
                        sizes="(max-width: 640px) 128px, 160px"
                        unoptimized
                        loading="eager"
                      />
                    </div>
                    <TypographyH3 className="mb-1 group-hover:text-primary transition-colors text-lg font-bold">
                      {leader.name}
                    </TypographyH3>
                    <TypographyPSmallMuted className="font-medium text-primary/80 mb-2 whitespace-pre-line">
                      {leader.position}
                    </TypographyPSmallMuted>
                    <div className="w-12 h-0.5 bg-primary/20 mb-3 group-hover:w-20 transition-all" />
                    <TypographyPSmallMuted className="italic">
                      Nhiệm kỳ: {LEADER_GENERATIONS[currentLeaderIndex].year}
                    </TypographyPSmallMuted>
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* Navigation Controls */}
          <div className="flex justify-center items-center gap-4 sm:gap-6 mt-8 sm:mt-12">
            <Button
              variant="outline"
              size="icon"
              onClick={prevLeader}
              className="rounded-full hover:bg-primary hover:text-white transition-all"
              aria-label="Thế hệ lãnh đạo trước"
            >
              <IconSize size="sm">
                <ChevronLeft />
              </IconSize>
            </Button>

            <div className="flex gap-2" role="group" aria-label="Chọn thế hệ lãnh đạo">
              {LEADER_GENERATIONS.map((_, index) => (
                <button
                  key={index}
                  onClick={() => setCurrentLeaderIndex(index)}
                  aria-label={`Thế hệ lãnh đạo ${LEADER_GENERATIONS[index].year}`}
                  aria-current={index === currentLeaderIndex ? "true" : "false"}
                  className={`h-2 rounded-full transition-all duration-300 ${
                    index === currentLeaderIndex
                      ? "bg-primary w-8"
                      : "bg-primary/20 w-2 hover:bg-primary/40"
                  }`}
                />
              ))}
            </div>

            <Button
              variant="outline"
              size="icon"
              onClick={nextLeader}
              className="rounded-full hover:bg-primary hover:text-white transition-all"
              aria-label="Thế hệ lãnh đạo tiếp theo"
            >
              <IconSize size="sm">
                <ChevronRight />
              </IconSize>
            </Button>
          </div>

          <div className="text-center mt-6">
            <TypographyPSmallMuted className="font-bold text-primary uppercase tracking-widest">
              {LEADER_GENERATIONS[currentLeaderIndex].period}
            </TypographyPSmallMuted>
          </div>
        </div>
      </div>
    </section>
  );
};

