  const [activeWordIndex, setActiveWordIndex] = useState(0);
  const sectionRef = useRef<HTMLElement>(null);
  const signIn = buttons?.[0]?.href ?? getAdminLoginUrl();
  const signUp = buttons?.[1]?.href ?? getAdminRegisterUrl();
