"use client";

import { useSyncExternalStore } from "react";

const noopSubscribe = () => () => {};

/**
 * `false` khi render trên server / trước hydrate, `true` trên client.
 * Dùng thay vì `useEffect` + `setState` để tránh cảnh báo ESLint.
 */
export function useClientReady(): boolean {
  return useSyncExternalStore(noopSubscribe, () => true, () => false);
}

src/hooks/use-debounced-value.ts.content:
"use client";

import { useEffect, useState } from "react";

/**
 * Trì hoãn cập nhật giá trị (tìm kiếm, sync URL) để giảm render / request.
 */
export function useDebouncedValue<T>(value: T, delayMs: number): T {
  const [debounced, setDebounced] = useState(value);

  useEffect(() => {
    const t = window.setTimeout(() => setDebounced(value), delayMs);
    return () => window.clearTimeout(t);
  }, [value, delayMs]);

  return debounced;
}

