import {
  Coffee,
  Droplets,
  Milk,
  Package2,
  Soup,
  UtensilsCrossed,
  Wheat,
  Box,
  Apple,
  Cookie,
  type LucideIcon,
} from "lucide-react";

const ICONS: Record<string, LucideIcon> = {
  Coffee,
  Droplets,
  Milk,
  Package2,
  Soup,
  UtensilsCrossed,
  Wheat,
  Box,
  Apple,
  Cookie,
};

export const CATEGORY_ICON_OPTIONS = Object.keys(ICONS);

export function resolveCategoryIcon(name?: string | null): LucideIcon {
  if (!name) return Package2;
  return ICONS[name] ?? Package2;
}

src/lib/dev-route-log.ts.content:
import { headers } from "next/headers";

type RouteLogMeta = {
  pathname: string;
  label?: string;
};

export async function logDevRouteHit({ pathname, label }: RouteLogMeta) {
  if (process.env.NODE_ENV !== "development") return;

  const headerStore = await headers();
  const referer = headerStore.get("referer") ?? "-";
  const userAgent = headerStore.get("user-agent") ?? "-";

  console.log(
    `[frontend][route] ${pathname} | ${label ?? "page"} | referer=${referer} | ua=${userAgent}`,
  );
}

src/lib/format.ts.content:
/** Format a numeric VND amount as "1.250.000đ". */
export const formatVND = (amount: number | null | undefined): string => {
  if (amount === null || amount === undefined || Number.isNaN(amount))
    return "—"
  return `${amount.toLocaleString("vi-VN")}đ`
}

/** Format an ISO date as "dd/MM/yyyy HH:mm" in vi-VN. */
export const formatDate = (iso: string | Date | undefined | null): string => {
  if (!iso) return "—"
  const date = iso instanceof Date ? iso : new Date(iso)
  if (Number.isNaN(date.getTime())) return "—"
  return date.toLocaleString("vi-VN", {
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
    hour: "2-digit",
    minute: "2-digit",
  })
}

/** Chỉ ngày — dùng cho bảng tóm tắt dữ liệu. */
export const formatDateShort = (
  iso: string | Date | undefined | null
): string => {
  if (!iso) return "—"
  const date = iso instanceof Date ? iso : new Date(iso)
  if (Number.isNaN(date.getTime())) return "—"
  return date.toLocaleDateString("vi-VN", {
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
  })
}

src/lib/public-posts.ts.content:
import { DEFAULT_API_URL } from "@workspace/api-client";

type ApiEnvelope<T> = {
  success: boolean;
  message?: string;
  error?: string | null;
  data?: T;
};

type PaginationMeta = {
  page: number;
  limit: number;
  total: number;
  totalPages: number;
};

type PublicPostCategory = {
  category: {
    name: string;
    slug: string;
  };
};

type PublicPostTag = {
  tag: {
    name: string;
    slug: string;
  };
};

type PublicPostAuthor = {
  name: string | null;
  avatar?: string | null;
};

export type PublicPostSummary = {
  id: string;
  title: string;
  slug: string;
  excerpt?: string | null;
  image?: string | null;
  publishedAt?: string | null;
  eventStartAt?: string | null;
  eventEndAt?: string | null;
  author?: PublicPostAuthor | null;
  categories: PublicPostCategory[];
  tags: PublicPostTag[];
  viewCount: number;
};

export type PublicPostDetail = PublicPostSummary & {
  content?: unknown | null;
};

type PublicPostsPayload = {
  data: PublicPostSummary[];
  meta: PaginationMeta;
};

export type PublicCategoryItem = {
  id: string;
  name: string;
  slug: string;
  description: string | null;
  parentId: string | null;
  parentName: string | null;
  _count: { children: number };
  postCount: number;
};

function getApiBaseUrl() {
  return (process.env.NEXT_PUBLIC_API_URL ?? DEFAULT_API_URL).replace(/\/$/, "");
}

function buildApiUrl(pathname: string, query?: Record<string, string | number | undefined>) {
  const url = new URL(`${getApiBaseUrl()}${pathname.startsWith("/") ? pathname : `/${pathname}`}`);

  if (query) {
    for (const [key, value] of Object.entries(query)) {
      if (value === undefined || value === null || value === "") continue;
      url.searchParams.set(key, String(value));
    }
  }

  return url.toString();
}

async function fetchPublicApi<T>(
  pathname: string,
  query?: Record<string, string | number | undefined>,
): Promise<T> {
  const url = buildApiUrl(pathname, query);
  const isDev = process.env.NODE_ENV === "development";

  if (isDev) {
    console.log(`[frontend][api] GET ${url}`);
  }

  const response = await fetch(url, {
    headers: {
      Accept: "application/json",
    },
    cache: isDev ? "no-store" : undefined,
    next: isDev ? undefined : { revalidate: 60 },
  });

  const payload = (await response.json().catch(() => null)) as ApiEnvelope<T> | null;

  if (!response.ok || !payload?.success || payload.data === undefined) {
    const message =
      payload?.message ||
      payload?.error ||
      `Request failed: ${response.status} ${response.statusText}`;
    throw new Error(message);
  }

  if (isDev) {
    console.log(`[frontend][api] ${response.status} ${pathname}`);
  }

  return payload.data;
}

export async function getPublicPosts(params?: {
  page?: number;
  limit?: number;
  categorySlug?: string;
  tagSlug?: string;
  search?: string;
}) {
  return fetchPublicApi<PublicPostsPayload>("/public/posts", params);
}

export async function getPublicCategories(params?: { slug?: string }) {
  return fetchPublicApi<PublicCategoryItem[]>("/public/categories", params);
}

export async function getPublicPostBySlug(slug: string) {
  try {
    return await fetchPublicApi<PublicPostDetail>(
      `/public/posts/${encodeURIComponent(slug)}`,
      { track: "false" },
    );
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    if (/not found/i.test(message)) return null;
    throw error;
  }
}

export function formatPostDate(value?: string | null) {
  if (!value) return null;

  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return null;

  return new Intl.DateTimeFormat("vi-VN", {
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
  }).format(date);
}

src/lib/scroll.ts.content:
"use client";

const getHeaderElement = () => document.querySelector("header");

export const getHeaderHeight = () => {
  const headerElement = getHeaderElement();
  return headerElement instanceof HTMLElement ? headerElement.offsetHeight : 0;
};

export const scrollToYWithHeaderOffset = (
  targetTop: number,
  behavior: ScrollBehavior = "smooth"
) => {
  const headerHeight = getHeaderHeight();
  const nextTop = Math.max(targetTop - headerHeight, 0);

  window.scrollTo({
    top: nextTop,
    left: 0,
    behavior,
  });
};

src/lib/seo.ts.content:
import type { Metadata } from "next"

export const SITE_NAME = "HUB Parent"
export const SITE_TITLE = "HUB Parent - Kết nối phụ huynh và nhà trường"
export const SITE_DESCRIPTION =
  "HUB Parent là hệ thống kết nối phụ huynh với Trường Đại học Ngân hàng TP.HCM, hỗ trợ theo dõi thông tin học tập, gửi liên hệ và cập nhật thông báo từ nhà trường."

export const SITE_URL = (
  process.env.NEXT_PUBLIC_SITE_URL ||
  process.env.NEXT_PUBLIC_FRONTEND_URL ||
  "https://hub.edu.vn"
).replace(/\/$/, "")

export const OG_IMAGE_URL =
  "https://fileserver2.hub.edu.vn/IMAGES/2025/12/16/20251216103027-101020.png"

export function absoluteUrl(path = "/"): string {
  return new URL(path, `${SITE_URL}/`).toString()
}

export function buildSeoMetadata({
  title,
  description = SITE_DESCRIPTION,
  path = "/",
  image = OG_IMAGE_URL,
  type = "website",
  noIndex = false,
}: {
  title?: string
  description?: string
  path?: string
  image?: string | null
  type?: "website" | "article"
  noIndex?: boolean
} = {}): Metadata {
  const resolvedTitle = title || SITE_TITLE
  const url = absoluteUrl(path)

  return {
    title: title ? resolvedTitle : { absolute: SITE_TITLE },
    description,
    alternates: {
      canonical: url,
    },
    robots: noIndex
      ? { index: false, follow: false }
      : {
          index: true,
          follow: true,
          googleBot: {
            index: true,
            follow: true,
            "max-image-preview": "large",
            "max-snippet": -1,
            "max-video-preview": -1,
          },
        },
    openGraph: {
      title: resolvedTitle,
      description,
      url,
      siteName: SITE_NAME,
      locale: "vi_VN",
      type,
      images: image
        ? [
            {
              url: image,
              alt: resolvedTitle,
            },
          ]
        : undefined,
    },
    twitter: {
      card: "summary_large_image",
      title: resolvedTitle,
      description,
      images: image ? [image] : undefined,
    },
  }
}

src/lib/storage.ts.content:
// Shared storage library to abstract LocalStorage usage
export const StorageLib = {
  get: <T>(key: string, defaultValue: T): T => {
    if (typeof window === 'undefined') return defaultValue;
    try {
      const item = window.localStorage.getItem(key);
      return item ? (JSON.parse(item) as T) : defaultValue;
    } catch (error) {
      console.warn(`Error reading localStorage key "${key}":`, error);
      return defaultValue;
    }
  },
  
  set: <T>(key: string, value: T): void => {
    if (typeof window === 'undefined') return;
    try {
      window.localStorage.setItem(key, JSON.stringify(value));
    } catch (error) {
      console.warn(`Error setting localStorage key "${key}":`, error);
    }
  }
};

